#!/usr/bin/env bash

set -euo pipefail

HOST="localhost"
USER="backup_user"
PASSWORD="BackupPass123"
BACKUP_DIR="${BACKUP_DIR:-/var/backups/mysql}"
DATE="$(date +%F_%H-%M-%S)"
MYSQL_OPTS=(-h "$HOST" -u "$USER" -p"$PASSWORD")

mkdir -p "$BACKUP_DIR"

databases="$(
  mysql "${MYSQL_OPTS[@]}" -N -B -e "SHOW DATABASES;" \
    | grep -Ev '^(information_schema|performance_schema|mysql|sys)$'
)"

for db in $databases; do
  outfile="$BACKUP_DIR/${db}_${DATE}.sql.gz"
  mysqldump "${MYSQL_OPTS[@]}" --single-transaction --routines --events --triggers "$db" | gzip > "$outfile"
done